import { useEffect, useRef } from 'react';
import './styles.css';

const BODY_HTML = "<canvas id=\"cosmos\"></canvas>\n<div class=\"haze haze-1\"></div>\n<div class=\"haze haze-2\"></div>\n<div class=\"cursor-dot\"></div>\n<div class=\"cursor-ring\"></div>\n\n<nav id=\"nav\">\n  <a class=\"nav-name\" href=\"#top\"><span class=\"dot\"></span>Tetiana Dovgalenko</a>\n  <div class=\"nav-links\">\n    <a class=\"keep\" href=\"resume.html\" target=\"_blank\" rel=\"noopener\">Resume</a>\n    <a href=\"https://www.linkedin.com/in/tanya-dovgalenko/\" target=\"_blank\" rel=\"noopener\">LinkedIn</a>\n    <a href=\"https://github.com/bllondis\" target=\"_blank\" rel=\"noopener\">Github</a>\n    <a class=\"keep\" href=\"#contact\">Contact</a>\n  </div>\n</nav>\n\n<main id=\"top\">\n\n  <header class=\"hero\">\n    <div class=\"hero-text\">\n      <div class=\"hero-eyebrow\"><span class=\"mono\">UX \u00b7 UI - Enterprise &amp; SaaS - AI</span></div>\n      <h1>\n        <span class=\"line\"><span>I design <em>calm</em></span></span>\n        <span class=\"line\"><span>interfaces for</span></span>\n        <span class=\"line\"><span>complex systems.</span></span>\n      </h1>\n      <p class=\"hero-sub\">Hello, I'm Tetiana Dovgalenko, a Product Designer and AI Design Engineer. Nice to meet you!</p>\n      <p class=\"hero-sub\">I love making design that's stylish and easy to use, usually inside complex systems with a lot of data behind them. With AI, I've grown into code and engineering tools, and it's reshaped how I design and build.</p>\n      <p class=\"hero-sub\">Originally from Kyiv, based in The Hague since 2018.</p>\n      <div class=\"hero-cta\">\n        <a class=\"btn btn-fill magnetic\" href=\"#work\">Explore the work <span class=\"arr\">\u2193</span></a>\n        <a class=\"btn btn-ghost magnetic\" href=\"#contact\">Get in touch</a>\n      </div>\n    </div>\n    <div class=\"hero-visual\">\n      <div class=\"portrait-wrap\">\n        <img class=\"portrait\" src=\"data:image/jpeg;base64,\" alt=\"Portrait of Tetiana Dovgalenko on the North Sea dunes\">\n        <div class=\"orbit-ring ring-a\"><span class=\"sat\"></span></div>\n        <div class=\"orbit-ring ring-b\"><span class=\"sat\"></span></div>\n      </div>\n    </div>\n  </header>\n\n  <div class=\"marquee\" aria-hidden=\"true\">\n    <div class=\"marquee-track\" id=\"marquee-track\">\n      <span>Enterprise UX <b>\u00b7</b> AI-assisted design <b>\u00b7</b> Design systems <b>\u00b7</b> Information architecture <b>\u00b7</b> Generative UI <b>\u00b7</b> Prototyping <b>\u00b7</b> Accessibility <b>\u00b7</b> Strategic thinking <b>\u00b7</b></span>\n    </div>\n  </div>\n\n  <section id=\"work\">\n    <div class=\"sec-head reveal\">\n      <h2>Selected <em>work</em></h2>\n      <span class=\"mono\">3 case studies \u00b7 2024 - 2026</span>\n    </div>\n    <p class=\"sec-intro reveal\">Three systems, three kinds of complexity - an AI product built solo, a live global ERP, and a legally regulated filing platform.</p>\n\n    <div class=\"orbit-stage reveal\" aria-hidden=\"true\">\n      <div class=\"orbit-system\">\n        <div class=\"o-ring r1\"></div><div class=\"o-ring r2\"></div><div class=\"o-ring r3\"></div>\n        <div class=\"hub\"><span class=\"mono\">Selected<br>work</span></div>\n        <div class=\"orb-path p1\"><a class=\"planet\" role=\"link\" tabindex=\"0\" data-go=\"#case-timeflow\" style=\"--planet-a:#FCFDFE;--planet-b:#AECBDD;--planet-c:#7CA2BC\">\n          <span class=\"foil\"></span>\n          <i>Timeflow</i>\n        </a></div>\n        <div class=\"orb-path p2\"><a class=\"planet\" role=\"link\" tabindex=\"0\" data-go=\"#case-bookit\" style=\"--planet-a:#FCFDFC;--planet-b:#BBD0C5;--planet-c:#89A89A\">\n          <span class=\"foil\"></span>\n          <i>BookIT</i>\n        </a></div>\n        <div class=\"orb-path p3\"><a class=\"planet\" role=\"link\" tabindex=\"0\" data-go=\"#case-docustream\" style=\"--planet-a:#FDFCFE;--planet-b:#C4C6E2;--planet-c:#9396BC\">\n          <span class=\"foil\"></span>\n          <i>DocuStream</i>\n        </a></div>\n      </div>\n    </div>\n\n    <article class=\"case reveal\" id=\"case-timeflow\">\n      <div class=\"case-art\" aria-hidden=\"true\">\n        <div class=\"case-orb\">\n          <img class=\"case-shot\" src=\"data:image/jpeg;base64,\" alt=\"\">\n          <svg class=\"case-orb-svg\" viewBox=\"0 0 200 200\" fill=\"none\">\n            <circle cx=\"100\" cy=\"100\" r=\"78\" stroke=\"#E3E7E6\"/>\n            <circle cx=\"100\" cy=\"100\" r=\"90\" stroke=\"#A9C6D9\" stroke-dasharray=\"3 4\"/>\n            <g class=\"rot\">\n              <circle cx=\"100\" cy=\"10\" r=\"2.6\" fill=\"#5F86A3\"/>\n              <circle cx=\"178\" cy=\"100\" r=\"1.7\" fill=\"#A9C6D9\"/>\n            </g>\n          </svg>\n        </div>\n      </div>\n      <div class=\"case-body\">\n        <div class=\"case-tag mono\">AI product \u00b7 2026 \u00b7 Solo build</div>\n        <h3>Timeflow - AI fills in the rest.</h3>\n        <p>An AI-powered timesheet assistant that reconstructs your workday from digital signals - so you confirm in seconds instead of rebuilding the week from memory. Designed, built and deployed solo.</p>\n        <div class=\"case-stats\">\n          <div class=\"stat\"><div class=\"num\">4<small> wks</small></div><div class=\"lab\">Concept \u2192 deployed</div></div>\n          <div class=\"stat\"><div class=\"num\">1</div><div class=\"lab\">Designer, front &amp; back end</div></div>\n          <div class=\"stat\"><div class=\"num\">10<small> s</small></div><div class=\"lab\">To confirm a day</div></div>\n        </div>\n        <a class=\"case-link link-planet\" href=\"cases/timeflow.html\">Read the case study <span class=\"cl-planet\" aria-hidden=\"true\"><span class=\"cl-foil\"></span><span class=\"cl-shade\"></span></span></a>\n      </div>\n    </article>\n\n    <article class=\"case reveal\" id=\"case-bookit\">\n      <div class=\"case-art\" aria-hidden=\"true\">\n        <div class=\"case-orb\">\n          <img class=\"case-shot\" src=\"data:image/jpeg;base64,\" alt=\"\">\n          <svg class=\"case-orb-svg\" viewBox=\"0 0 200 200\" fill=\"none\">\n            <circle cx=\"100\" cy=\"100\" r=\"78\" stroke=\"#E3E7E6\"/>\n            <circle cx=\"100\" cy=\"100\" r=\"90\" stroke=\"#A9C6D9\" stroke-dasharray=\"3 4\"/>\n            <g class=\"rot\">\n              <circle cx=\"100\" cy=\"10\" r=\"2.6\" fill=\"#5F86A3\"/>\n              <circle cx=\"178\" cy=\"100\" r=\"1.7\" fill=\"#A9C6D9\"/>\n            </g>\n          </svg>\n        </div>\n      </div>\n      <div class=\"case-body\">\n        <div class=\"case-tag mono\">Enterprise ERP \u00b7 2024 - 25</div>\n        <h3>Six new modules for a live global ERP.</h3>\n        <p>New admin modules added to a deeply branched enterprise system serving offices worldwide - designed to feel like they had always been there.</p>\n        <div class=\"case-stats\">\n          <div class=\"stat\"><div class=\"num\">200K+</div><div class=\"lab\">Active users</div></div>\n          <div class=\"stat\"><div class=\"num\">40+</div><div class=\"lab\">Countries, 1,200+ offices</div></div>\n          <div class=\"stat\"><div class=\"num\">85K</div><div class=\"lab\">Reservations a day</div></div>\n        </div>\n        <a class=\"case-link link-planet planet-sage\" href=\"cases/bookit.html\">Read the case study <span class=\"cl-planet\" aria-hidden=\"true\"><span class=\"cl-foil\"></span><span class=\"cl-shade\"></span></span></a>\n      </div>\n    </article>\n\n    <article class=\"case reveal\" id=\"case-docustream\">\n      <div class=\"case-art\" aria-hidden=\"true\">\n        <div class=\"case-orb\">\n          <img class=\"case-shot\" src=\"data:image/jpeg;base64,\" alt=\"\">\n          <svg class=\"case-orb-svg\" viewBox=\"0 0 200 200\" fill=\"none\">\n            <circle cx=\"100\" cy=\"100\" r=\"78\" stroke=\"#E3E7E6\"/>\n            <circle cx=\"100\" cy=\"100\" r=\"90\" stroke=\"#A9C6D9\" stroke-dasharray=\"3 4\"/>\n            <g class=\"rot\">\n              <circle cx=\"100\" cy=\"10\" r=\"2.6\" fill=\"#5F86A3\"/>\n              <circle cx=\"178\" cy=\"100\" r=\"1.7\" fill=\"#A9C6D9\"/>\n            </g>\n          </svg>\n        </div>\n      </div>\n      <div class=\"case-body\">\n        <div class=\"case-tag mono\">Legal-tech SaaS \u00b7 2025 - 26</div>\n        <h3>Designing clarity into a high-stakes filing system.</h3>\n        <p>An end-to-end platform for UCC filings - a regulated process where a single error has material consequences. Built to carry complexity without dumping it on the user.</p>\n        <div class=\"case-stats\">\n          <div class=\"stat\"><div class=\"num\">100+</div><div class=\"lab\">Document types</div></div>\n          <div class=\"stat\"><div class=\"num\">6</div><div class=\"lab\">User roles</div></div>\n          <div class=\"stat\"><div class=\"num\">7+</div><div class=\"lab\">Filing statuses</div></div>\n        </div>\n        <a class=\"case-link link-planet planet-peri\" href=\"cases/docustream.html\">Read the case study <span class=\"cl-planet\" aria-hidden=\"true\"><span class=\"cl-foil\"></span><span class=\"cl-shade\"></span></span></a>\n      </div>\n    </article>\n  </section>\n\n  <section id=\"approach\" class=\"approach\">\n    <div class=\"sec-head reveal\">\n      <h2>How I <em>think</em></h2>\n      <span class=\"mono\">Strategy \u2192 systems \u2192 screens</span>\n    </div>\n    <div class=\"principles\">\n      <div class=\"principle reveal\">\n        <div class=\"glyph\"><svg viewBox=\"0 0 120 64\" fill=\"none\">\n          <line x1=\"10\" y1=\"50\" x2=\"50\" y2=\"14\"/><line x1=\"50\" y1=\"14\" x2=\"86\" y2=\"38\"/><line x1=\"86\" y1=\"38\" x2=\"112\" y2=\"10\"/>\n          <circle cx=\"10\" cy=\"50\" r=\"3.5\" fill=\"#5F86A3\"/><circle cx=\"50\" cy=\"14\" r=\"3.5\" fill=\"#A9C6D9\"/><circle cx=\"86\" cy=\"38\" r=\"3.5\" fill=\"#A9C6D9\"/><circle cx=\"112\" cy=\"10\" r=\"3.5\" fill=\"#5F86A3\"/>\n        </svg></div>\n        <h4>Systems before screens</h4>\n        <p>Before design, a decade of strategy and programme management - from shaping cultural policy for a capital city to running film productions. I map the whole system before drawing the first screen.</p>\n      </div>\n      <div class=\"principle reveal\">\n        <div class=\"glyph\"><svg viewBox=\"0 0 120 64\" fill=\"none\">\n          <line x1=\"18\" y1=\"32\" x2=\"60\" y2=\"32\"/><line x1=\"60\" y1=\"32\" x2=\"84\" y2=\"12\"/><line x1=\"60\" y1=\"32\" x2=\"84\" y2=\"52\"/><line x1=\"84\" y1=\"12\" x2=\"108\" y2=\"12\"/><line x1=\"84\" y1=\"52\" x2=\"108\" y2=\"52\"/>\n          <circle cx=\"18\" cy=\"32\" r=\"3.5\" fill=\"#5F86A3\"/><circle cx=\"60\" cy=\"32\" r=\"3.5\" fill=\"#A9C6D9\"/><circle cx=\"108\" cy=\"12\" r=\"3.5\" fill=\"#5F86A3\"/><circle cx=\"108\" cy=\"52\" r=\"3.5\" fill=\"#5F86A3\"/>\n        </svg></div>\n        <h4>AI as a design material</h4>\n        <p>AI isn't just a faster way to work - it's a new layer of the product. I design with it, prototype with it, and used it to take Timeflow from idea to deployed code in four weeks.</p>\n      </div>\n      <div class=\"principle reveal\">\n        <div class=\"glyph\"><svg viewBox=\"0 0 120 64\" fill=\"none\">\n          <line x1=\"10\" y1=\"14\" x2=\"42\" y2=\"50\"/><line x1=\"42\" y1=\"50\" x2=\"74\" y2=\"14\"/><line x1=\"74\" y1=\"14\" x2=\"74\" y2=\"50\"/><line x1=\"74\" y1=\"50\" x2=\"110\" y2=\"50\"/>\n          <circle cx=\"10\" cy=\"14\" r=\"3.5\" fill=\"#A9C6D9\"/><circle cx=\"42\" cy=\"50\" r=\"3.5\" fill=\"#A9C6D9\"/><circle cx=\"74\" cy=\"14\" r=\"3.5\" fill=\"#A9C6D9\"/><circle cx=\"110\" cy=\"50\" r=\"3.5\" fill=\"#5F86A3\"/>\n        </svg></div>\n        <h4>Complexity is the brief. Clarity is the deliverable.</h4>\n        <p>Enterprise platforms live on edge cases - thousands of states, roles and exceptions. My job is to absorb that complexity so the people using the product never feel it.</p>\n      </div>\n    </div>\n  </section>\n\n  <section id=\"beyond\" class=\"beyond\">\n    <div class=\"sec-head reveal\">\n      <h2>Beyond the <em>screen</em></h2>\n      <span class=\"mono\">Photography \u00b7 costume \u00b7 painting</span>\n    </div>\n    <p class=\"sec-intro reveal\">Before pixels, I designed with fabric, light and composition - six years as a costume artist in film production, a degree in art history, painting, and a camera that still goes everywhere with me.</p>\n    <div class=\"vogue-note reveal\"><span class=\"v\">VOGUE</span><span class=\"mono\" style=\"letter-spacing:.12em\">Photographs from this series published in Vogue's online gallery</span></div>\n\n    <div class=\"constellation reveal\" id=\"constellation\">\n      <svg id=\"const-lines\" aria-hidden=\"true\"><path id=\"const-path\" d=\"\"/></svg>\n      <div class=\"photo-grid\">\n        <figure class=\"photo ph-1\"><img src=\"data:image/jpeg;base64,\" alt=\"Double rainbow over black volcanic sand at Sk\u00f3gafoss waterfall, Iceland\"><figcaption class=\"cap\">01 - Sk\u00f3gafoss, Iceland</figcaption></figure>\n        <figure class=\"photo ph-2\"><img src=\"data:image/jpeg;base64,\" alt=\"A lone figure standing in the mist of a waterfall, Iceland\"><figcaption class=\"cap\">02 - Into the mist, Iceland</figcaption></figure>\n        <figure class=\"photo ph-3\"><img src=\"data:image/jpeg;base64,\" alt=\"A boy sitting on rocks by a cascading waterfall\"><figcaption class=\"cap\">03 - Falls study</figcaption></figure>\n        <figure class=\"photo ph-4\"><img src=\"data:image/jpeg;base64,\" alt=\"Winter light on the North Sea coast, the Netherlands\"><figcaption class=\"cap\">04 - North Sea coast, NL</figcaption></figure>\n        <figure class=\"photo ph-5\"><img src=\"data:image/jpeg;base64,\" alt=\"Silhouettes of herons on city rooftops, black and white\"><figcaption class=\"cap\">05 - City herons</figcaption></figure>\n      </div>\n    </div>\n  </section>\n\n  <section id=\"contact\" class=\"contact\">\n    <span class=\"mono reveal\">Next orbit</span>\n    <h2 class=\"reveal\">Let's build something <em>clear.</em></h2>\n    <p class=\"sub reveal\">Open to product design opportunities in the Netherlands.</p>\n    <div class=\"reveal\"><a class=\"email-link\" href=\"mailto:tetiana.dovgalenko@gmail.com\">tetiana.dovgalenko@gmail.com</a></div>\n    <div class=\"contact-row reveal\">\n      <a href=\"https://linkedin.com/in/tanya-dovgalenko\" target=\"_blank\" rel=\"noopener\">LinkedIn \u2197</a>\n      <span class=\"mono\" style=\"align-self:center\">The Hague, NL - 52.07\u00b0 N, 4.30\u00b0 E</span>\n    </div>\n  </section>\n\n</main>\n\n<footer>\n  <span class=\"mono\">\u00a9 2026 Tetiana Dovgalenko</span>\n  <span class=\"mono\">Designed as a small cosmos</span>\n</footer>";

const SCRIPT = "(function(){\n  var reduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;\n  var finePointer = window.matchMedia('(pointer: fine)').matches;\n\n  /* duplicate marquee content for seamless loop */\n  var track = document.getElementById('marquee-track');\n  track.innerHTML += track.innerHTML;\n\n  /* load sequence */\n  window.addEventListener('load', function(){ document.body.classList.add('loaded'); });\n  setTimeout(function(){ document.body.classList.add('loaded'); }, 900);\n\n  /* nav scroll state */\n  var nav = document.getElementById('nav');\n  window.addEventListener('scroll', function(){\n    nav.classList.toggle('scrolled', window.scrollY > 40);\n  }, {passive:true});\n\n  /* reveal on scroll */\n  var io = new IntersectionObserver(function(entries){\n    entries.forEach(function(e){\n      if(e.isIntersecting){ e.target.classList.add('in'); io.unobserve(e.target); }\n    });\n  }, {threshold:0.12});\n  document.querySelectorAll('.reveal').forEach(function(el){ io.observe(el); });\n\n  /* constellation lines */\n  var constellation = document.getElementById('constellation');\n  var constSvg = document.getElementById('const-lines');\n  var constPath = document.getElementById('const-path');\n  function drawConstellation(){\n    if(!constellation) return;\n    var rect = constellation.getBoundingClientRect();\n    if(rect.width < 10) return;\n    constSvg.setAttribute('viewBox','0 0 '+rect.width+' '+rect.height);\n    var pts = [];\n    constellation.querySelectorAll('.photo').forEach(function(ph){\n      var r = ph.getBoundingClientRect();\n      pts.push([r.left - rect.left + r.width/2, r.top - rect.top + r.height/2]);\n    });\n    if(pts.length < 2) return;\n    var d = 'M' + pts.map(function(p){ return p[0].toFixed(1)+' '+p[1].toFixed(1); }).join(' L');\n    constPath.setAttribute('d', d);\n    var len = constPath.getTotalLength();\n    constPath.style.setProperty('--len', len);\n  }\n  window.addEventListener('resize', drawConstellation);\n  window.addEventListener('load', drawConstellation);\n  setTimeout(drawConstellation, 400);\n\n  /* ---------- planets -> smooth-scroll to matching case (no link nav, works in any frame) ---------- */\n  function goToCase(sel){\n    var el = sel && document.querySelector(sel);\n    if(!el) return;\n    el.scrollIntoView({behavior: reduced ? 'auto' : 'smooth', block:'start'});\n  }\n  document.querySelectorAll('.planet').forEach(function(p){\n    var target = p.getAttribute('data-go');\n    if(!target) return;\n    p.addEventListener('click', function(e){ e.preventDefault(); goToCase(target); });\n    p.addEventListener('keydown', function(e){\n      if(e.key === 'Enter' || e.key === ' '){ e.preventDefault(); goToCase(target); }\n    });\n  });\n\n  if(reduced) return; /* everything below is motion */\n\n  /* ---------- custom cursor ---------- */\n  if(finePointer){\n    document.body.classList.add('has-cursor');\n    var dot = document.querySelector('.cursor-dot');\n    var ring = document.querySelector('.cursor-ring');\n    var mx = innerWidth/2, my = innerHeight/2, rx = mx, ry = my;\n    document.addEventListener('mousemove', function(e){ mx = e.clientX; my = e.clientY; });\n    (function loopCursor(){\n      rx += (mx - rx) * 0.16; ry += (my - ry) * 0.16;\n      dot.style.transform = 'translate('+(mx-3.5)+'px,'+(my-3.5)+'px)';\n      ring.style.left = rx+'px'; ring.style.top = ry+'px';\n      if(!ring.classList.contains('is-hover')) ring.style.transform = 'translate(-50%,-50%)';\n      requestAnimationFrame(loopCursor);\n    })();\n    document.querySelectorAll('a, button, .planet, .photo').forEach(function(el){\n      el.addEventListener('mouseenter', function(){ ring.classList.add('is-hover'); });\n      el.addEventListener('mouseleave', function(){ ring.classList.remove('is-hover'); });\n    });\n\n    /* pause orbit only when cursor is directly on the planet sphere */\n    document.querySelectorAll('.planet').forEach(function(planet){\n      var path = planet.closest('.orb-path');\n      planet.addEventListener('mouseenter', function(){\n        if(path) path.style.animationPlayState = 'paused';\n        planet.style.animationPlayState = 'paused';\n      });\n      planet.addEventListener('mouseleave', function(){\n        if(path) path.style.animationPlayState = 'running';\n        planet.style.animationPlayState = 'running';\n      });\n    });\n  }\n\n  /* ---------- magnetic buttons ---------- */\n  if(finePointer){\n    document.querySelectorAll('.magnetic').forEach(function(btn){\n      btn.addEventListener('mousemove', function(e){\n        var r = btn.getBoundingClientRect();\n        var x = e.clientX - r.left - r.width/2;\n        var y = e.clientY - r.top - r.height/2;\n        btn.style.transform = 'translate('+(x*0.22)+'px,'+(y*0.3)+'px)';\n      });\n      btn.addEventListener('mouseleave', function(){\n        btn.style.transition = 'transform .5s cubic-bezier(.16,1,.3,1)';\n        btn.style.transform = '';\n        setTimeout(function(){ btn.style.transition=''; }, 500);\n      });\n    });\n  }\n\n  /* ---------- particle cosmos ---------- */\n  var canvas = document.getElementById('cosmos');\n  var ctx = canvas.getContext('2d');\n  var W, H, dpr = Math.min(window.devicePixelRatio || 1, 2);\n  var particles = [];\n  var mouse = {x:-9999, y:-9999};\n  var COLORS = ['rgba(95,134,163,', 'rgba(169,198,217,', 'rgba(150,160,168,'];\n\n  function sizeCanvas(){\n    W = innerWidth; H = innerHeight;\n    canvas.width = W*dpr; canvas.height = H*dpr;\n    canvas.style.width = W+'px'; canvas.style.height = H+'px';\n    ctx.setTransform(dpr,0,0,dpr,0,0);\n  }\n  function makeParticles(){\n    particles = [];\n    var n = Math.min(120, Math.floor(W*H/14000));\n    for(var i=0;i<n;i++){\n      particles.push({\n        x: Math.random()*W, y: Math.random()*H,\n        vx: (Math.random()-.5)*0.22, vy: (Math.random()-.5)*0.22,\n        r: 0.8 + Math.random()*1.7,\n        c: COLORS[(Math.random()*COLORS.length)|0],\n        a: 0.25 + Math.random()*0.45\n      });\n    }\n  }\n  sizeCanvas(); makeParticles();\n  window.addEventListener('resize', function(){ sizeCanvas(); makeParticles(); });\n  document.addEventListener('mousemove', function(e){ mouse.x = e.clientX; mouse.y = e.clientY; });\n  document.addEventListener('mouseleave', function(){ mouse.x = -9999; mouse.y = -9999; });\n\n  var running = true;\n  document.addEventListener('visibilitychange', function(){ running = !document.hidden; });\n\n  function frame(){\n    requestAnimationFrame(frame);\n    if(!running) return;\n    ctx.clearRect(0,0,W,H);\n    var i, j, p, q;\n    for(i=0;i<particles.length;i++){\n      p = particles[i];\n      /* gentle gravity toward cursor */\n      var dx = mouse.x - p.x, dy = mouse.y - p.y;\n      var d2 = dx*dx + dy*dy;\n      if(d2 < 32400){ /* 180px */\n        var d = Math.sqrt(d2) || 1;\n        var f = (1 - d/180) * 0.045;\n        p.vx += dx/d * f; p.vy += dy/d * f;\n      }\n      p.vx *= 0.985; p.vy *= 0.985;\n      /* keep a minimum drift */\n      p.x += p.vx + Math.sin((p.y + i*40)*0.004)*0.06;\n      p.y += p.vy + 0.04;\n      if(p.x < -10) p.x = W+10; if(p.x > W+10) p.x = -10;\n      if(p.y < -10) p.y = H+10; if(p.y > H+10) p.y = -10;\n      ctx.beginPath();\n      ctx.arc(p.x, p.y, p.r, 0, 6.2832);\n      ctx.fillStyle = p.c + p.a + ')';\n      ctx.fill();\n    }\n    /* constellation links between near particles */\n    ctx.lineWidth = 0.6;\n    for(i=0;i<particles.length;i++){\n      for(j=i+1;j<particles.length;j++){\n        p = particles[i]; q = particles[j];\n        var ddx = p.x-q.x, ddy = p.y-q.y;\n        var dd = ddx*ddx + ddy*ddy;\n        if(dd < 5600){ /* ~75px */\n          ctx.strokeStyle = 'rgba(95,134,163,' + (0.10*(1-dd/5600)).toFixed(3) + ')';\n          ctx.beginPath(); ctx.moveTo(p.x,p.y); ctx.lineTo(q.x,q.y); ctx.stroke();\n        }\n      }\n    }\n  }\n  frame();\n})();";

export default function App() {
  const ref = useRef(null);
  useEffect(() => {
    // run the original site script after the markup is in the DOM
    const s = document.createElement('script');
    s.textContent = SCRIPT;
    document.body.appendChild(s);
    return () => { s.remove(); };
  }, []);
  return <div ref={ref} dangerouslySetInnerHTML={{ __html: BODY_HTML }} />;
}
